# Priority order: try each provider until one works.
# Skip providers without API key configured.

FALLBACK_CHAIN = [
    "groq",
    "cerebras",
    "mistral",
    "openai",
    "claude",
    "mimo",
]

def _has_key(name):
    """Check if provider has API key configured."""
    keys = {
        "groq": config.GROQ_API_KEY,
        "cerebras": config.CEREBRAS_API_KEY,
        "mistral": config.MISTRAL_API_KEY,
        "openai": config.OPENAI_API_KEY,
        "claude": config.ANTHROPIC_API_KEY,
        "mimo": config.MIMO_API_KEY,
    }
    return bool(keys.get(name))

def get_fallback_provider():
    """Return list of providers that have API keys, in fallback order."""
    providers = []
    for name in FALLBACK_CHAIN:
        if _has_key(name):
            try:
                providers.append((name, get_provider(name)))
            except Exception:
                pass
    if not providers:
        raise ValueError("Tidak ada provider dengan API key terkonfigurasi!")
    return providers

class FallbackProvider:
    """Wrapper that tries providers in order until one succeeds."""

    def __init__(self):
        self._providers = get_fallback_provider()
        self._current_idx = 0
        self.name = self._providers[0][0]
        self.provider = self._providers[0][1]
        self.model = self.provider.model
        self.context_window = self.provider.context_window
        self._fail_counts = {}
        self._MAX_FAILS = 3  # skip provider after 3 consecutive fails

    def _next_provider(self):
        """Switch to next available provider."""
        self._current_idx = (self._current_idx + 1) % len(self._providers)
        name, prov = self._providers[self._current_idx]
        self.name = name
        self.provider = prov
        self.model = prov.model
        self.context_window = prov.context_window

